-- =============================================
-- All Iron Sports - Club Migration
-- Run in Supabase SQL editor
-- =============================================

-- STEP 1: Delete non-club entries
DELETE FROM clubs WHERE name IN ('Free Agent', 'Intermediary', 'Agent', 'AGENT', 'Investor', 'Unemployed', 'Unknown', 'TBD', '4SportAgency', 'Ludonautics', 'Global Football Holdings', 'Luis Campos', 'Ares Management', 'Zelus', '11Hacks', 'FC Förderkader');

-- STEP 2: Fix Scottish clubs wrongly assigned to other countries
UPDATE clubs SET country = 'Scotland', league = 'Scottish Premiership'
WHERE name IN ('Aberdeen', 'Celtic', 'Rangers', 'Heart of Midlothian', 'Hearts', 'Hibernian', 'Kilmarnock', 'Livingston', 'Motherwell', 'St Mirren', 'St Johnstone', 'Dundee', 'Dundee United', 'Ross County', 'Hamilton Academical', 'Inverness CT', 'Partick Thistle', 'Ayr United') AND country != 'Scotland';

-- STEP 3: Insert all clubs (skip if name already exists)
ON CONFLICT DO NOTHING;

-- Done! Check results:
SELECT country, league, COUNT(*) FROM clubs GROUP BY country, league ORDER BY country, league;